import arrow from "./arrow.svg";
import { Banner } from "./banner.style";
import {
  LandingPage,
  Heading,
  Arrow,
  Landing,
} from "./landing.style";
import {
  ScrollLanding,
  // ScrollUp,
} from "./scroll.style"
import { Page } from "./webpage.style";

function App() {
  const [landing, setLanding] = useState(true);
  return (
    <>
    {landing && <Landing>
    <ScrollLanding id="landing" href="#page" onClick={setTimeout(() => {
      setLanding(false)
    }, 3000)}>
          <LandingPage className="landing-page">
            <Heading> e g a &nbsp; c h e u n g </Heading>
            <Arrow tabIndex={-1} src={arrow} alt="arrow" />
          </LandingPage>
        </ScrollLanding>
        </Landing>}

      <Page id="page">
        <Banner/>
        {/* <ScrollUp href="#landing"></ScrollUp> */}
      </Page>
    </>
  );
}

export default App;
